<script setup lang="ts">
import {reactive,ref} from 'vue';import {runPrecheck} from './api/precheck';import type {PrecheckRequest,PrecheckResponse} from './types/precheck';
const form=reactive<PrecheckRequest>({title:'模拟环境查询响应变慢',description:'模拟数据：上午开始查询响应时间增加，需要辅助梳理排查信息。',product:'Inceptor',module:'SQL Engine',version:'',severity:'P2',impactScope:'单个模拟任务',attachmentsSummary:''});
const loading=ref(false),error=ref(''),submitted=ref(false);const result=ref<PrecheckResponse>();
async function precheck(){error.value='';result.value=undefined;if(!form.title.trim()||!form.description.trim()){error.value='请先填写标题和问题描述；仍可继续人工提交。';return}loading.value=true;try{result.value=await runPrecheck(form)}catch(e){error.value=e instanceof Error?`${e.message}；可以继续人工提交。`:'预诊失败；可以继续人工提交。'}finally{loading.value=false}}
function continueSubmit(){submitted.value=true}
</script>
<template><header><div><span class="brand">TRANSWARP</span><strong>Service Insight</strong></div><span class="badge">技术 MVP · 模拟数据</span></header><main><section class="intro"><p class="eyebrow">SLA 智能预诊助手</p><h1>在提交前，把问题描述得更完整</h1><p>Mock API 仅生成辅助建议，不代表最终根因或处理结论；SLA 是否提交由人工确认。</p></section><div class="layout"><form class="card" @submit.prevent="precheck"><h2>新建 SLA</h2><label>标题 *<input v-model="form.title" /></label><label>问题描述 *<textarea v-model="form.description" rows="5" /></label><div class="grid"><label>产品<input v-model="form.product" /></label><label>模块<input v-model="form.module" /></label><label>版本<input v-model="form.version" /></label><label>紧急程度<select v-model="form.severity"><option value="">请选择</option><option>P1</option><option>P2</option><option>P3</option></select></label></div><label>影响范围<input v-model="form.impactScope" /></label><label>附件摘要（仅限模拟或脱敏内容）<textarea v-model="form.attachmentsSummary" rows="2" /></label><div class="actions"><button class="primary" :disabled="loading">{{loading?'正在预诊…':'智能预诊'}}</button><button type="button" class="secondary" @click="continueSubmit">继续提交 SLA</button></div><p v-if="submitted" class="notice">已进入人工确认步骤（模拟），未调用真实提交接口。</p></form><aside class="card result"><h2>预诊结果</h2><div v-if="loading" class="empty">正在调用本地 Mock API…</div><div v-else-if="error" class="error">{{error}}</div><div v-else-if="result"><div class="meta"><span>置信度 {{result.confidence}}</span><span>必须人工审核</span></div><h3>辅助摘要</h3><p>{{result.summary}}</p><h3>建议</h3><ul><li v-for="item in result.recommendations" :key="item">{{item}}</li></ul><h3>依据来源</h3><article v-for="item in result.references" :key="item.url" class="reference"><strong>{{item.title}}</strong><p>{{item.excerpt}}</p><a :href="item.url" target="_blank">模拟链接</a></article><template v-if="result.missingInformation.length"><h3>待补充信息</h3><div class="chips"><span v-for="item in result.missingInformation" :key="item">{{item}}</span></div></template><p class="fallback">{{result.fallbackReason}}</p></div><div v-else class="empty">填写表单后点击“智能预诊”，结果将在这里展示。</div></aside></div></main></template>
